// Runtime: kind guards compare numeric TSKindId only (Phase D).
function _g(id: number): (v: { readonly $type: number }) => boolean {
    return (v) => v.$type === id;
}
function _sg(ids: ReadonlySet<number>): (v: { readonly $type: number }) => boolean {
    return (v) => ids.has(v.$type);
}

